mapper.update:
UPDATE ai_client_rag_order
rag_id = #{ragId}, rag_name = #{ragName}, knowledge_tag = #{knowledgeTag}, status = #{status}, update_time = #{updateTime},
WHERE id = #{id}

mapper.select:
SELECT id, rag_id, rag_name, knowledge_tag, status, create_time, update_time
FROM ai_client_rag_order
WHERE id = #{id}

SELECT id, rag_id, rag_name, knowledge_tag, status, create_time, update_time
FROM ai_client_rag_order
WHERE rag_id = #{ragId}

SELECT id, rag_id, rag_name, knowledge_tag, status, create_time, update_time
FROM ai_client_rag_order

    AND rag_id = #{ragId}
    AND rag_name LIKE CONCAT('%', #{ragName}, '%')
    AND knowledge_tag = #{knowledgeTag}
    AND status = #{status}

ORDER BY create_time DESC
